# pseudo-code: agent's per-finding loop
def handle(finding):
    if (finding.kind in SYNTACTIC
        and finding.tool.has_fix(finding.rule_id)):
        diff = finding.tool.fix(finding.path)
        if run_tests().ok and (diff.lines < 50 or diff.single_rule_id):
            stage(diff)
            return "auto-applied"
    return flag_for_human(finding)

def handle(finding):
    # "agent decides" — apply or flag based on confidence score
    if finding.confidence > 0.8:
        finding.tool.fix(finding.path)
